// // This module generates a pulse of a specified width when a trigger signal is received.
// Inputs:
// - clk: a 50MHz clock signal
// - trigger: a 1-bit trigger signal that goes low for a single clock cycle when the pulse is to be generated
// - pulse_width: a 16-bit value that specifies the width of the pulse in clock cycles
// Outputs:
// - pulse: a 1-bit signal that goes low when the pulse is being generated
module pulse_gen(
  input clk,
  input trigger,
  input [15:0] pulse_width,
  output reg pulse
);

reg [15:0] counter = 0;
reg pulse_gen = 0;

always @(posedge clk) begin
  if (trigger) begin
    pulse_gen <= 1;
    counter <= 0;
  end else begin
    if (counter >= pulse_width) begin
      pulse_gen <= 0;
    end
    counter <= counter + 1;
  end
end

always @(posedge clk) begin
  pulse <= pulse_gen;
end

endmodule

